MI_DATA.filterByWilayah = function(wCode) {
  if (!wCode) return this.records;
  return this.records.filter(r => r.wilayah_kode === wCode);
};

MI_DATA.getSummary = function(wCode) {
  var sw = wCode ? this.summaryWilayah.filter(w => w.wilayah_kode === wCode) : this.summaryWilayah;
  var sum = function(arr, k) { return arr.reduce(function(a,b){return a+b[k];},0).toFixed(2); };
  return {
    dpk_outstanding:      +sum(sw,'dpk_outstanding'),
    dpk_target:           +sum(sw,'dpk_target'),
    lending_outstanding:  +sum(sw,'lending_outstanding'),
    lending_target:       +sum(sw,'lending_target'),
    kk_outstanding:       +sum(sw,'kk_outstanding'),
    kk_target:            +sum(sw,'kk_target'),
    merchant_outstanding: +sum(sw,'merchant_outstanding'),
    merchant_target:      +sum(sw,'merchant_target'),
    total_nasabah:        sw.reduce(function(a,b){return a+b.total_nasabah;},0),
  };
};

MI_DATA.getKKByWilayah = function(wCode) {
  if (!wCode) return this.kualitasKredit;
  return this.kualitasKredit.filter(r => r.wilayah === wCode);
};

// Usage example (console):
// MI_DATA.getSummary()         → total semua wilayah
// MI_DATA.getSummary('W04')    → hanya Jakarta Pusat
// MI_DATA.filterByWilayah('W09') → 1000 records filtered Surabaya
// MI_DATA.getKKByWilayah('W06')  → kualitas kredit Bandung
